            "name": "ref-napi",
            "native": true
          },
          {
            "name": "farmhash",
            "native": true
          },
          {
            "name": "bcrypt",
            "native": true
          },
          {
            "name": "ffi-napi",
            "native": true
          },
          {
            "name": "@newrelic/native-metrics",
            "native": true
          },
          {
            "name": "level",
